#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;double ans=0;
    cin>>n;
    if(n<150){
    	ans+=n*0.4463;
        printf("%.1lf",ans);
        return 0;
	}
	else{
		ans+=150*0.4463;
		n-=150;
	}
    if(n<250){
    	ans+=n*0.4663;
        printf("%.1lf",ans);
        return 0;
	}
	else{
		ans+=250*0.4663;
		n-=250;
	}
    if(n)ans+=n*0.5663;
    printf("%.1lf",ans);
    return 0;
}
